&lt;p data-renderer-start-pos=&quot;3073&quot; data-local-id=&quot;27b6b372-b656-4cc7-b8b5-0181e9f74f92&quot;&gt;&lt;strong data-renderer-mark=&quot;true&quot;&gt;Responsibilities&lt;/strong&gt;&lt;/p&gt;
